cumsum.metal_source:
// cumsum: 2-level prefix scan using hardware simd_prefix_inclusive_sum.
// 2 threadgroup barriers vs 20 for Hillis-Steele.
#include <metal_stdlib>
using namespace metal;

kernel void cumsum_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;        // simdgroup index (0..31)
    const uint sl = t & 31;         // lane within simdgroup (0..31)

    float val = x[row * N + t];

    // Level 1: simdgroup scan (hardware-accelerated, no barrier)
    float local_scan = simd_prefix_inclusive_sum(val);

    // Last lane in each simdgroup holds the group's total sum
    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Level 2: first simdgroup computes exclusive scan over the 32 totals.
    // After this, thread sl (if sg==0) holds the offset for simdgroup sl.
    float my_offset = 0.0f;
    if (sg == 0) {
        my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    }
    // Broadcast: thread sl writes the offset for simdgroup sl.
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Each thread adds its simdgroup's offset.
    y[row * N + t] = local_scan + tg_totals[sg];
}

cumprod.metal_source:
// cumprod: 2-level prefix product using hardware simd_prefix_inclusive_product.
// 2 threadgroup barriers.
#include <metal_stdlib>
using namespace metal;

kernel void cumprod_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;
    const uint sl = t & 31;

    float val = x[row * N + t];

    // Level 1: simdgroup prefix product
    float local_scan = simd_prefix_inclusive_product(val);

    // Last lane holds group total
    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Level 2: exclusive scan over group totals
    float my_offset = 0.0f;
    if (sg == 0) {
        // For product scan, we need 1.0 (identity) as the starting point
        my_offset = simd_prefix_exclusive_product(tg_totals[sl]);
    }
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Add offset -> multiply offset
    y[row * N + t] = local_scan * tg_totals[sg];
}

cumsum_reverse.metal_source:
// cumsum_reverse: 2-level prefix scan on reversed elements per row.
#include <metal_stdlib>
using namespace metal;

kernel void cumsum_reverse_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5, sl = t & 31;
    const uint rev_t = N - 1 - t;

    float val = x[row * N + rev_t];
    float local_scan = simd_prefix_inclusive_sum(val);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[row * N + rev_t] = local_scan + tg_totals[sg];
}

mse_loss.metal_source:
// mse_loss: mean((pred - target)^2). Single-tg simdgroup reduction.
#include <metal_stdlib>
using namespace metal;

kernel void mse_loss_f32(
    device const float*  pred    [[buffer(0)]],
    device const float*  target  [[buffer(1)]],
    device       float*  out     [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    uint  tid                   [[thread_position_in_threadgroup]])
{
    const uint tg_size = 1024;
    float sum = 0.0f;
    const uint N4 = N / 4;
    device const float4* pred4 = reinterpret_cast<device const float4*>(pred);
    device const float4* targ4 = reinterpret_cast<device const float4*>(target);
    for (uint i = tid; i < N4; i += tg_size) {
        float4 d = pred4[i] - targ4[i];
        sum += d.x*d.x + d.y*d.y + d.z*d.z + d.w*d.w;
    }

    float sg_sum = simd_sum(sum);

    threadgroup float tg_sum[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) tg_sum[sg] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sg_sum = tg_sum[tid];
        for (uint s = 16; s > 0; s >>= 1)
            sg_sum += simd_shuffle_down(sg_sum, s);
    }
    if (tid == 0) *out = sg_sum / float(N);
}

matvec.metal_source:
// matvec: y = A @ x. One threadgroup per row, simd_sum reduction.
#include <metal_stdlib>
using namespace metal;

kernel void matvec_f32(
    device const float*  A  [[buffer(0)]],
    device const float*  x  [[buffer(1)]],
    device       float*  y  [[buffer(2)]],
    constant     uint&   N  [[buffer(3)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    float sum = A[row * N + t] * x[t];
    float sg_sum = simd_sum(sum);

    threadgroup float tg[32];
    uint sg = t >> 5;
    if ((t & 31) == 0) tg[sg] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sg_sum = tg[t];
        for (uint s = 16; s > 0; s >>= 1)
            sg_sum += simd_shuffle_down(sg_sum, s);
    }
    if (t == 0) y[row] = sg_sum;
}

transpose_2d.metal_source:
// transpose_2d: B = A^T. Tiled 32x32 via threadgroup memory.
#include <metal_stdlib>
using namespace metal;

kernel void transpose_2d_f32(
    device const float*  A       [[buffer(0)]],
    device       float*  B       [[buffer(1)]],
    constant     uint&   M       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TILE = 32;
    threadgroup float tile[TILE][TILE + 1];
    const uint r = tid.x / TILE;
    const uint c = tid.x % TILE;
    const uint row = tgid.y * TILE + r;
    const uint col = tgid.x * TILE + c;

    if (row < M && col < N)
        tile[r][c] = A[row * N + col];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint out_row = tgid.x * TILE + r;
    const uint out_col = tgid.y * TILE + c;
    if (out_row < N && out_col < M)
        B[out_row * M + out_col] = tile[c][r];
}

outer_product.metal_source:
// outer_product: C[i][j] = x[i] * y[j]. Float4, memory-bound.
#include <metal_stdlib>
using namespace metal;

kernel void outer_product_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  y       [[buffer(1)]],
    device       float*  C       [[buffer(2)]],
    constant     uint&   M       [[buffer(3)]],
    constant     uint&   N       [[buffer(4)]],
    uint  tid                   [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    const uint total4 = M * n4;
    for (uint idx4 = tid; idx4 < total4; idx4 += grid_size) {
        uint i = idx4 / n4;
        uint j4 = idx4 % n4;
        float xi = x[i];
        float4 yv = *(reinterpret_cast<const device float4*>(&y[j4 * 4]));
        *(reinterpret_cast<device float4*>(&C[i * N + j4 * 4])) = xi * yv;
    }
    for (uint idx = n4 * 4 + tid; idx < M * N; idx += grid_size) {
        C[idx] = x[idx / N] * y[idx % N];
    }
}

matrix_add.metal_source:
// matrix_add: C = A + B. Float4 grid-stride, memory-bound.
#include <metal_stdlib>
using namespace metal;

kernel void matrix_add_f32(
    device const float*  A         [[buffer(0)]],
    device const float*  B         [[buffer(1)]],
    device       float*  C         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]],
    uint  grid_size               [[threads_per_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 a = *(reinterpret_cast<const device float4*>(&A[i * 4]));
        float4 b = *(reinterpret_cast<const device float4*>(&B[i * 4]));
        *(reinterpret_cast<device float4*>(&C[i * 4])) = a + b;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        C[i] = A[i] + B[i];
}

dot_product.metal_source:
// dot_product: x^T y. Single reduction via simd_sum + cross-simdgroup sum.
#include <metal_stdlib>
using namespace metal;

kernel void dot_product_f32(
    device const float*  x  [[buffer(0)]],
    device const float*  y  [[buffer(1)]],
    device       float*  out [[buffer(2)]],
    constant     uint&   N  [[buffer(3)]],
    uint  tid              [[thread_position_in_threadgroup]])
{
    const uint tg_size = 1024;
    float sum = 0.0f;
    for (uint i = tid; i < N; i += tg_size)
        sum += x[i] * y[i];

    float sg_sum = simd_sum(sum);

    threadgroup float tg[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) tg[sg] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sg_sum = tg[tid];
        for (uint s = 16; s > 0; s >>= 1)
            sg_sum += simd_shuffle_down(sg_sum, s);
    }
    if (tid == 0) *out = sg_sum;
}

matrix_scale.metal_source:
// matrix_scale: B = alpha * A. Float4 grid-stride, memory-bound.
#include <metal_stdlib>
using namespace metal;

kernel void matrix_scale_f32(
    device const float*  A     [[buffer(0)]],
    device       float*  B     [[buffer(1)]],
    constant     uint&   N     [[buffer(2)]],
    constant     float&  alpha [[buffer(3)]],
    uint  tid                 [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&A[i * 4]));
        *(reinterpret_cast<device float4*>(&B[i * 4])) = alpha * v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        B[i] = alpha * A[i];
}

softmax.metal_source:
// softmax per row: simd_max + simd_sum reductions.
#include <metal_stdlib>
using namespace metal;

kernel void softmax_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * N;
    const uint sg = t >> 5;
    const uint lane = t & 31;

    threadgroup float tg_buf[32];
    threadgroup float row_max;
    threadgroup float row_sum;

    float val = x[off + t];

    // ---- max reduction ----
    float m = simd_max(val);
    if (lane == 0) tg_buf[sg] = m;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float v = tg_buf[lane];
        v = simd_max(v);
        if (lane == 0) row_max = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float rmax = row_max;

    // ---- exp + sum reduction ----
    float ev = exp(val - rmax);
    float s = simd_sum(ev);
    if (lane == 0) tg_buf[sg] = s;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float v = tg_buf[lane];
        v = simd_sum(v);
        if (lane == 0) row_sum = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[off + t] = ev / row_sum;
}

tanh.metal_source:
// tanh: float4 grid-stride, memory-bound.
#include <metal_stdlib>
using namespace metal;

kernel void tanh_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = tanh(v);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        y[i] = tanh(x[i]);
}

hardswish.metal_source:
// hardswish: x * clamp(x+3, 0, 6) / 6. Float4 grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void hardswish_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v * clamp(v + 3.0f, 0.0f, 6.0f) / 6.0f;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        y[i] = x[i] * clamp(x[i] + 3.0f, 0.0f, 6.0f) / 6.0f;
}

cosine_similarity.metal_source:
// cosine_similarity: x·y / (|x| * |y|) per row. Three simd_sum reductions.
#include <metal_stdlib>
using namespace metal;

kernel void cosine_similarity_f32(
    device const float*  x   [[buffer(0)]],
    device const float*  y   [[buffer(1)]],
    device       float*  out [[buffer(2)]],
    constant     uint&   D   [[buffer(3)]],
    uint3 tid               [[thread_position_in_threadgroup]],
    uint3 tgid              [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * D;
    const uint sg = t >> 5;

    float xi = x[off + t];
    float yi = y[off + t];
    float dot_v = xi * yi;
    float sq_x  = xi * xi;
    float sq_y  = yi * yi;

    float dot_sum  = simd_sum(dot_v);
    float sq_x_sum = simd_sum(sq_x);
    float sq_y_sum = simd_sum(sq_y);

    threadgroup float tg_dot[32], tg_sqx[32], tg_sqy[32];
    if ((t & 31) == 0) {
        tg_dot[sg] = dot_sum;
        tg_sqx[sg] = sq_x_sum;
        tg_sqy[sg] = sq_y_sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        float d = tg_dot[t], sx = tg_sqx[t], sy = tg_sqy[t];
        for (uint s = 16; s > 0; s >>= 1) {
            d  += simd_shuffle_down(d,  s);
            sx += simd_shuffle_down(sx, s);
            sy += simd_shuffle_down(sy, s);
        }
        if (t == 0) {
            float eps = 1e-8f;
            out[row] = d / (sqrt(sx) * sqrt(sy) + eps);
        }
    }
}

manhattan_similarity.metal_source:
// manhattan_similarity: L1 distance per row. simd_sum(|x - y|).
#include <metal_stdlib>
using namespace metal;

kernel void manhattan_similarity_f32(
    device const float*  x   [[buffer(0)]],
    device const float*  y   [[buffer(1)]],
    device       float*  out [[buffer(2)]],
    constant     uint&   D   [[buffer(3)]],
    uint3 tid               [[thread_position_in_threadgroup]],
    uint3 tgid              [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * D;
    const uint sg = t >> 5;

    float sum = simd_sum(fabs(x[off + t] - y[off + t]));

    threadgroup float tg[32];
    if ((t & 31) == 0) tg[sg] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sum = tg[t];
        for (uint s = 16; s > 0; s >>= 1)
            sum += simd_shuffle_down(sum, s);
    }
    if (t == 0) out[row] = sum;
}

add_norm.metal_source:
// add_norm: y = layer_norm(x + residual). Fused add + norm in one pass.
#include <metal_stdlib>
using namespace metal;

kernel void add_norm_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  res     [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * D;

    float val = x[off + t] + res[off + t]; // Fused add
    float s2  = val * val;

    float sum   = simd_sum(val);
    float sumsq = simd_sum(s2);

    threadgroup float tg_sum[32], tg_sumsq[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) { tg_sum[sg] = sum; tg_sumsq[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sum = tg_sum[t]; sumsq = tg_sumsq[t];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
    }
    if (t == 0) { tg_sum[0] = sum; tg_sumsq[0] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_sum[0] / float(D);
    float var  = max(tg_sumsq[0] / float(D) - mean * mean, 0.0f);
    float inv_std = rsqrt(var + eps);

    y[off + t] = (val - mean) * inv_std;
}

silu_linear.metal_source:
// silu_linear: y = silu(x @ W). Fused matmul + SiLU in store phase.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM  = 64, BN  = 64, BK  = 16;
constant constexpr uint SM  = 16, SN  = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;

kernel void silu_linear_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float As[2][BM * LDA], Bs[2][BK * LDB];
    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM, c_col0 = tgid.x * BN;
    const uint a_row = lid / 4, a_c4 = lid % 4, b_row = lid / 16, b_c4 = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    { // Prologue
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    const uint num_k_tiles = K / BK; uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf, k0_nxt = (kt + 1) * BK;
        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup); buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    // Store to device memory then in-place activate via per-thread loop.
    // Each thread writes its portion, then immediately re-reads + activates.
    // The data is in L2 cache, so re-read is nearly free.
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                &C[(c_row0 + sm*SM + i*8) * N + (c_col0 + sn*SN + j*8)], N);

    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Each thread activates a subset of the output tile using float4
    const uint total_float4 = BM * BN / 4;
    for (uint idx = lid; idx < total_float4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        if (c_row0 + r >= M || c_col0 + c >= N) continue;
        device float4* ptr = reinterpret_cast<device float4*>(&C[(c_row0 + r) * N + (c_col0 + c)]);
        float4 v = *ptr;
        *ptr = v / (1.0f + exp(-v));
    }
}

conv2d.metal_source:
// conv2d: direct NHWC convolution. Input (N,H,W,C), weight (K,R,S,C), output (N,H2,W2,K).
#include <metal_stdlib>
using namespace metal;

kernel void conv2d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]], constant     uint&   C       [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]], constant     uint&   W       [[buffer(6)]],
    constant     uint&   K       [[buffer(7)]], constant     uint&   R       [[buffer(8)]],
    constant     uint&   S       [[buffer(9)]], constant     uint&   stride  [[buffer(10)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - R) / stride + 1, W2 = (W - S) / stride + 1;
    const uint total = N * K * H2 * W2;
    for (uint idx = tid; idx < total; idx += 64*1024) {
        uint n = idx / (K * H2 * W2), r = idx % (K * H2 * W2);
        uint k = r / (H2 * W2), p = r % (H2 * W2);
        uint h2 = p / W2, w2 = p % W2;
        float sum = 0;
        for (uint c = 0; c < C; c++)
            for (uint rr = 0; rr < R; rr++)
                for (uint ss = 0; ss < S; ss++)
                    sum += x[((n*H+h2*stride+rr)*W+w2*stride+ss)*C+c] * w[((k*R+rr)*S+ss)*C+c];
        y[((n*H2+h2)*W2+w2)*K+k] = sum;
    }
}

exp.metal_source:
// exp: out = exp(x). Stub: scalar grid-stride. Replace with optimized version.
