batch_norm.metal_source:
// batchnorm: normalize each column over rows. (1024, 256) input.
// Strided simdgroup reduction over 1024 elements per column.
#include <metal_stdlib>
using namespace metal;

kernel void batch_norm_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint col = tgid.y;

    float val = x[t * C + col];
    float s2  = val * val;

    float sum   = simd_sum(val);
    float sumsq = simd_sum(s2);

    threadgroup float tg_sum[32];
    threadgroup float tg_sumsq[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) {
        tg_sum[sg]   = sum;
        tg_sumsq[sg] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sum   = tg_sum[t];
        sumsq = tg_sumsq[t];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
    }
    if (t == 0) {
        tg_sum[0]   = sum;
        tg_sumsq[0] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_sum[0] / float(N);
    float var  = max(tg_sumsq[0] / float(N) - mean * mean, 0.0f);
    float inv_std = rsqrt(var + eps);

    y[t * C + col] = (val - mean) * inv_std;
}

elu.metal_source:
// elu: x if x>0 else α*(exp(x)-1). 1024 thr/tg, float4, grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void elu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    constant     float&  alpha     [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 neg = alpha * (exp(v) - 1.0f);
        float4 out = select(neg, v, v > 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = out;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = v > 0.0f ? v : alpha * (exp(v) - 1.0f);
    }
}

mish.metal_source:
// mish: x * tanh(softplus(x)). Stable softplus = max(x,0) + log1p(exp(-|x|)).
#include <metal_stdlib>
using namespace metal;

static inline float4 softplus4(float4 v) {
    float4 ax = fabs(v);
    float4 mx = fmax(v, 0.0f);
    return mx + log(1.0f + exp(-ax));
}

kernel void mish_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 sp = softplus4(v);
        *reinterpret_cast<device float4*>(&y[i * 4]) = v * tanh(sp);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        float sp = fmax(v, 0.0f) + log(1.0f + exp(-fabs(v)));
        y[i] = v * tanh(sp);
    }
}

softplus.metal_source:
// softplus: log(1 + exp(x)). Stable form: max(x,0) + log1p(exp(-|x|)).
#include <metal_stdlib>
using namespace metal;

kernel void softplus_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 ax = fabs(v);
        float4 mx = fmax(v, 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = mx + log(1.0f + exp(-ax));
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = fmax(v, 0.0f) + log(1.0f + exp(-fabs(v)));
    }
}

prelu.metal_source:
// prelu: x if x>0 else alpha[c]*x. Per-channel slope.
// Shape: x is (N, C), alpha is (C,). Layout assumed row-major: x[n*C + c].
#include <metal_stdlib>
using namespace metal;

kernel void prelu_f32(
    device const float*  x         [[buffer(0)]],
    device const float*  alpha     [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N_total   [[buffer(3)]],
    constant     uint&   C         [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N_total; i += grid_size) {
        float v = x[i];
        uint c = i % C;
        float a = alpha[c];
        y[i] = v > 0.0f ? v : a * v;
    }
}

argmax.metal_source:
// argmax: per-row argmax along last dim. One threadgroup per row.
// Input (R, C). Output index as float (harness expects f32 outputs).
#include <metal_stdlib>
using namespace metal;

kernel void argmax_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  out     [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* row_ptr = x + row * C;

    float best_v = -INFINITY;
    uint  best_i = 0;
    for (uint i = tid; i < C; i += TG) {
        float v = row_ptr[i];
        if (v > best_v) { best_v = v; best_i = i; }
    }

    threadgroup float tg_v[32];
    threadgroup uint  tg_i[32];

    // Simdgroup reduction: pick max-value lane, propagate its index.
    for (uint s = 16; s > 0; s >>= 1) {
        float ov = simd_shuffle_down(best_v, s);
        uint  oi = simd_shuffle_down(best_i, s);
        if (ov > best_v) { best_v = ov; best_i = oi; }
    }
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_v[sg] = best_v; tg_i[sg] = best_i; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        best_v = tg_v[tid];
        best_i = tg_i[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            float ov = simd_shuffle_down(best_v, s);
            uint  oi = simd_shuffle_down(best_i, s);
            if (ov > best_v) { best_v = ov; best_i = oi; }
        }
        if (tid == 0) out[row] = float(best_i);
    }
}

variance.metal_source:
// variance: per-row Var(x) = mean(x²) − mean(x)². One threadgroup per row.
#include <metal_stdlib>
using namespace metal;

kernel void variance_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  out     [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* row_ptr = x + row * C;

    float sum = 0.0f, sumsq = 0.0f;
    for (uint i = tid; i < C; i += TG) {
        float v = row_ptr[i];
        sum   += v;
        sumsq += v * v;
    }

    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    threadgroup float tg_s[32], tg_q[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sum   = tg_s[tid];
        sumsq = tg_q[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
        if (tid == 0) {
            float mean = sum / float(C);
            out[row] = sumsq / float(C) - mean * mean;
        }
    }
}

rope_embedding.metal_source:
// rope_embedding: rotary position embedding. Input (S, D), D even.
// Per (s, i) where i in [0, D/2): rotate pair (x[s,2i], x[s,2i+1]).
#include <metal_stdlib>
using namespace metal;

kernel void rope_embedding_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   S         [[buffer(2)]],
    constant     uint&   D         [[buffer(3)]],
    constant     float&  base      [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint half_d = D / 2;
    const uint total  = S * half_d;
    if (tid >= total) return;

    const uint s = tid / half_d;
    const uint i = tid % half_d;
    float omega = 1.0f / pow(base, (2.0f * float(i)) / float(D));
    float ang = float(s) * omega;
    float c = cos(ang), sn = sin(ang);

    float x0 = x[s * D + 2 * i];
    float x1 = x[s * D + 2 * i + 1];
    y[s * D + 2 * i]     = x0 * c - x1 * sn;
    y[s * D + 2 * i + 1] = x0 * sn + x1 * c;
}

swiglu.metal_source:
// swiglu: silu(x @ W_gate) * (x @ W_up).
// One thread per output element. Output (M, N).
#include <metal_stdlib>
using namespace metal;

kernel void swiglu_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  Wg      [[buffer(1)]],
    device const float*  Wu      [[buffer(2)]],
    device       float*  Y       [[buffer(3)]],
    constant     uint&   M       [[buffer(4)]],
    constant     uint&   N       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    uint  tid                   [[thread_position_in_grid]])
{
    if (tid >= M * N) return;
    const uint m = tid / N;
    const uint n = tid % N;

    float g = 0.0f, u = 0.0f;
    for (uint k = 0; k < K; ++k) {
        float xk = X[m * K + k];
        g += xk * Wg[k * N + n];
        u += xk * Wu[k * N + n];
    }
    float silu_g = g / (1.0f + exp(-g));
    Y[m * N + n] = silu_g * u;
}

softmax_attention.metal_source:
// softmax_attention: softmax(Q @ K^T / sqrt(D)) @ V. S=128, D=64.
// One TG per query row. TG=1024.
#include <metal_stdlib>
using namespace metal;

kernel void softmax_attention_f32(
    device const float*  Q       [[buffer(0)]],
    device const float*  K       [[buffer(1)]],
    device const float*  V       [[buffer(2)]],
    device       float*  O       [[buffer(3)]],
    constant     uint&   S       [[buffer(4)]],
    constant     uint&   D       [[buffer(5)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint qr = tgid.y;
    if (qr >= S) return;

    threadgroup float qrow[64];
    threadgroup float scores[128];
    threadgroup float reduce[32];
    threadgroup float tmp[64 * 16];

    for (uint d = tid; d < D; d += TG) qrow[d] = Q[qr * D + d];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float inv = rsqrt(float(D));
    if (tid < S) {
        device const float* kr = K + tid * D;
        float dot = 0.0f;
        for (uint d = 0; d < D; ++d) dot += qrow[d] * kr[d];
        scores[tid] = dot * inv;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float v = (tid < S) ? scores[tid] : -INFINITY;
    float mx = simd_max(v);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float m = (tid < 4) ? reduce[tid] : -INFINITY;
        m = simd_max(m);
        if (tid == 0) reduce[0] = m;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float e = (tid < S) ? fast::exp(scores[tid] - row_max) : 0.0f;
    if (tid < S) scores[tid] = e;
    float sum = simd_sum(e);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float s = (tid < 4) ? reduce[tid] : 0.0f;
        s = simd_sum(s);
        if (tid == 0) reduce[0] = s;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_sum = 1.0f / reduce[0];

    // Normalize scores in-place.
    if (tid < S) scores[tid] = scores[tid] * inv_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Output: O[qr, d] = sum_j scores[j] * V[j, d]. D=64, first 64 threads.
    // Output: O[qr, d] = sum_j scores[j] * V[j, d]. D=64, S=128.
    // Use all 1024 threads: tid = j_lane * D + d, with j_lane in [0, 16), d in [0, 64).
    // Each (j_lane, d) accumulates S/16 = 8 entries, then we reduce across j_lane.
    if (tid < 1024) {
        uint d = tid & 63;
        uint j_lane = tid >> 6;          // 0..15
        const uint J_GROUPS = 16;
        const uint per = S / J_GROUPS;   // 8
        float acc = 0.0f;
        uint j_start = j_lane * per;
        for (uint j = j_start; j < j_start + per; ++j) acc += scores[j] * V[j * D + d];
        // Reduce across j_lane (16 partials per d).
        tmp[d * 16 + j_lane] = acc;
        threadgroup_barrier(mem_flags::mem_threadgroup);
        if (j_lane == 0) {
            float s = 0.0f;
            for (uint k = 0; k < 16; ++k) s += tmp[d * 16 + k];
            O[qr * D + d] = s;
        }
    }
}

residual_add.metal_source:
// residual_add: y = x + alpha * residual. Vectorized: single float4 per thread.
#include <metal_stdlib>
using namespace metal;

kernel void residual_add_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  R       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  alpha   [[buffer(5)]],
    uint tid                    [[thread_position_in_grid]])
{
    // N = 1024*1024 = 1<<20. grid_size = 64*1024 = 1<<16.
    // Each thread does N/grid_size = 16 floats = 4 float4s.
    const uint n4 = N >> 2;           // 1<<18
    const float a = alpha;
    // Use base = tid*4 then stride grid_size in float4 units.
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 r = *reinterpret_cast<const device float4*>(&R[base]);
        *reinterpret_cast<device float4*>(&Y[base]) = x + a * r;
    }
}

dropout.metal_source:
// dropout (inverted): y = mask * x * (1/(1-p)). float4 grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void dropout_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  M       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  p       [[buffer(5)]],
    uint tid                    [[thread_position_in_grid]])
{
    const float scale = 1.0f / (1.0f - p);
    const uint n4 = N >> 2;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 m = *reinterpret_cast<const device float4*>(&M[base]);
        *reinterpret_cast<device float4*>(&Y[base]) = m * x * scale;
    }
}

instance_norm.metal_source:
// instance_norm: normalize per-sample per-channel over (H, W).
// Layout (N, C, H, W). One threadgroup per (n, c) block, reduces H*W elements.
#include <metal_stdlib>
using namespace metal;

kernel void instance_norm_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     float&  eps     [[buffer(6)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint nc = tgid.y;
    const uint HW = H * W;
    device const float* base_in  = X + nc * HW;
    device       float* base_out = Y + nc * HW;

    float sum = 0.0f, sumsq = 0.0f;
    for (uint i = tid; i < HW; i += TG) {
        float v = base_in[i];
        sum   += v;
        sumsq += v * v;
    }
    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    threadgroup float tg_s[32], tg_q[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sum   = tg_s[tid];
        sumsq = tg_q[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
        if (tid == 0) { tg_s[0] = sum; tg_q[0] = sumsq; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_s[0] / float(HW);
    float var  = max(tg_q[0] / float(HW) - mean * mean, 0.0f);
    float inv  = rsqrt(var + eps);
    for (uint i = tid; i < HW; i += TG)
        base_out[i] = (base_in[i] - mean) * inv;
}

group_norm.metal_source:
// group_norm: normalize per-sample per-group over (CG, H, W) where CG = C/G.
// One threadgroup per (n, g) block, reduces CG*H*W elements.
#include <metal_stdlib>
using namespace metal;

kernel void group_norm_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   G       [[buffer(6)]],
    constant     float&  eps     [[buffer(7)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint ng  = tgid.y;     // 0 .. N*G - 1
    const uint n   = ng / G;
    const uint g   = ng % G;
    const uint CG  = C / G;
    const uint block = CG * H * W;
    device const float* base_in  = X + (n * C + g * CG) * H * W;
    device       float* base_out = Y + (n * C + g * CG) * H * W;

    float sum = 0.0f, sumsq = 0.0f;
    for (uint i = tid; i < block; i += TG) {
        float v = base_in[i];
        sum   += v;
        sumsq += v * v;
    }
    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    threadgroup float tg_s[32], tg_q[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum   = tg_s[tid];
        sumsq = tg_q[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
        if (tid == 0) { tg_s[0] = sum; tg_q[0] = sumsq; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_s[0] / float(block);
    float var  = max(tg_q[0] / float(block) - mean * mean, 0.0f);
    float inv  = rsqrt(var + eps);
    for (uint i = tid; i < block; i += TG)
        base_out[i] = (base_in[i] - mean) * inv;
}

cross_entropy_loss.metal_source:
// cross_entropy_loss: per-row -sum(y_onehot * log_softmax(logits)).
// Output shape (N,). One threadgroup per row.
#include <metal_stdlib>
using namespace metal;

kernel void cross_entropy_loss_f32(
    device const float*  L        [[buffer(0)]],   // logits (N, C)
    device const float*  Yh       [[buffer(1)]],   // one-hot (N, C)
    device       float*  out      [[buffer(2)]],   // (N,)
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* lp = L  + row * C;
    device const float* yp = Yh + row * C;

    threadgroup float reduce[32];

    float mx = -INFINITY;
    for (uint i = tid; i < C; i += TG) mx = fmax(mx, lp[i]);
    mx = simd_max(mx);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        mx = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) mx = fmax(mx, simd_shuffle_down(mx, s));
        if (tid == 0) reduce[0] = mx;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float sum = 0.0f;
    for (uint i = tid; i < C; i += TG) sum += exp(lp[i] - row_max);
    sum = simd_sum(sum);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) sum += simd_shuffle_down(sum, s);
        if (tid == 0) reduce[0] = sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float lse = row_max + log(reduce[0]);

    float nll = 0.0f;
    for (uint i = tid; i < C; i += TG) nll += yp[i] * (lse - lp[i]);
    nll = simd_sum(nll);
    if ((tid & 31) == 0) reduce[tid >> 5] = nll;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        nll = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) nll += simd_shuffle_down(nll, s);
        if (tid == 0) out[row] = nll;
    }
}

log_softmax.metal_source:
// log_softmax: y = x - logsumexp(x). One TG per row.
#include <metal_stdlib>
using namespace metal;

kernel void log_softmax_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* xr = X + row * C;
    device       float* yr = Y + row * C;

    threadgroup float reduce[32];

    float mx = -INFINITY;
    for (uint i = tid; i < C; i += TG) {
        float v = xr[i];
        yr[i] = v;  // stash for reuse
        mx = fmax(mx, v);
    }
    mx = simd_max(mx);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        mx = simd_max(reduce[tid]);
        if (tid == 0) reduce[0] = mx;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float sum = 0.0f;
    for (uint i = tid; i < C; i += TG) sum += fast::exp(yr[i] - row_max);
    sum = simd_sum(sum);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum = simd_sum(reduce[tid]);
        if (tid == 0) reduce[0] = sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float lse = row_max + fast::log(reduce[0]);

    for (uint i = tid; i < C; i += TG) yr[i] = yr[i] - lse;
}

masked_softmax.metal_source:
// masked_softmax: y = softmax(x + mask). Per-row.
#include <metal_stdlib>
using namespace metal;

kernel void masked_softmax_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  M       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* xr = X + row * C;
    device const float* mr = M + row * C;
    device       float* yr = Y + row * C;

    threadgroup float reduce[32];

    float mx = -INFINITY;
    for (uint i = tid; i < C; i += TG) mx = fmax(mx, xr[i] + mr[i]);
    mx = simd_max(mx);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        mx = simd_max(reduce[tid]);
        if (tid == 0) reduce[0] = mx;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float sum = 0.0f;
    for (uint i = tid; i < C; i += TG) {
        float e = fast::exp(xr[i] + mr[i] - row_max);
        yr[i] = e;  // store for second pass to avoid recompute
        sum += e;
    }
    sum = simd_sum(sum);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum = simd_sum(reduce[tid]);
        if (tid == 0) reduce[0] = sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv = 1.0f / reduce[0];

    for (uint i = tid; i < C; i += TG) yr[i] = yr[i] * inv;
}

bias_add.metal_source:
// bias_add: y[r, c] = x[r, c] + b[c]. float4 grid-stride loop.
#include <metal_stdlib>
using namespace metal;

kernel void bias_add_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  B        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   N_total  [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint tid                     [[thread_position_in_grid]])
{
    const uint n4 = N_total >> 2;
    const uint Cmask = C - 1; // C is 1024
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 b = *reinterpret_cast<const device float4*>(&B[base & Cmask]);
        *reinterpret_cast<device float4*>(&Y[base]) = x + b;
    }
}

fused_add_rms_norm.metal_source:
// fused_add_rms_norm: y = (x+r) * rsqrt(mean((x+r)^2) + eps). Per-row.
#include <metal_stdlib>
using namespace metal;

kernel void fused_add_rms_norm_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  R       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* xr = X + row * D;
    device const float* rr = R + row * D;
    device       float* yr = Y + row * D;

    threadgroup float reduce[32];

    float sumsq = 0.0f;
    for (uint i = tid; i < D; i += TG) {
        float v = xr[i] + rr[i];
        sumsq += v * v;
    }
    sumsq = simd_sum(sumsq);
    if ((tid & 31) == 0) reduce[tid >> 5] = sumsq;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sumsq = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) sumsq += simd_shuffle_down(sumsq, s);
        if (tid == 0) reduce[0] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv = rsqrt(reduce[0] / float(D) + eps);
    for (uint i = tid; i < D; i += TG) yr[i] = (xr[i] + rr[i]) * inv;
}

linear_bias.metal_source:
// linear_bias: y = x @ W + b. (M,K) @ (K,N) + (N,). M=N=K=256.
// Grid: 1D, 256 thr/tg. Each TG processes 256 contiguous output elements
// — exactly one full row of N=256 outputs.
#include <metal_stdlib>
using namespace metal;

kernel void linear_bias_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  W        [[buffer(1)]],
    device const float*  B        [[buffer(2)]],
    device       float*  Y        [[buffer(3)]],
    constant     uint&   M        [[buffer(4)]],
    constant     uint&   N        [[buffer(5)]],
    constant     uint&   K        [[buffer(6)]],
    uint tid                     [[thread_position_in_grid]],
    uint lid                     [[thread_position_in_threadgroup]],
    uint tgid                    [[threadgroup_position_in_grid]])
{
    threadgroup float xrow[256];     // K = 256
    threadgroup float brow[256];     // N = 256
    const uint m = tgid;             // row index
    if (m >= M) return;

    // Cooperatively load X row (K=256) and bias (N=256). Both 256 floats with 256 threads.
    xrow[lid] = X[m * K + lid];
    brow[lid] = B[lid];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Each thread computes one output col n = lid.
    const uint n = lid;
    float acc = brow[n];
    #pragma unroll(8)
    for (uint k = 0; k < K; ++k) acc += xrow[k] * W[k * N + n];
    Y[m * N + n] = acc;
}

bias_gelu.metal_source:
// bias_gelu: y = gelu(x + b). float4 with cached bias in threadgroup memory.
#include <metal_stdlib>
using namespace metal;

// Tanh-approx GELU: 0.5*x*(1 + tanh(sqrt(2/pi) * (x + 0.044715*x^3))).
// MLX baseline uses this approximation too (default for mlx.nn.gelu_approx).
// For safety we use precise erf via fast_precise tanh.
static inline float gelu_fast(float x) {
    const float k0 = 0.7978845608f;  // sqrt(2/pi)
    const float k1 = 0.044715f;
    float x3 = x * x * x;
    float t = k0 * (x + k1 * x3);
    return 0.5f * x * (1.0f + precise::tanh(t));
}

// erf-based GELU using polynomial approx (A&S 7.1.26).
static inline float gelu_erf_approx(float x) {
    const float k = 0.70710678f; // 1/sqrt(2)
    float z = x * k;
    float t = 1.0f / (1.0f + 0.3275911f * fabs(z));
    float y = 1.0f - (((((1.061405429f * t - 1.453152027f) * t)
              + 1.421413741f) * t - 0.284496736f) * t + 0.254829592f)
              * t * exp(-z * z);
    float erfz = copysign(y, z);
    return 0.5f * x * (1.0f + erfz);
}

kernel void bias_gelu_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  B        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   N_total  [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint tid                       [[thread_position_in_grid]],
    uint lid                       [[thread_position_in_threadgroup]],
    uint tg_size                   [[threads_per_threadgroup]])
{
    threadgroup float bias_tg[1024];
    for (uint i = lid; i < C; i += tg_size) bias_tg[i] = B[i];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint n4 = N_total >> 2;
    const uint Cmask = C - 1;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 b = *reinterpret_cast<const threadgroup float4*>(&bias_tg[base & Cmask]);
        float4 z = x + b;
        float4 r;
        r.x = gelu_erf_approx(z.x);
        r.y = gelu_erf_approx(z.y);
        r.z = gelu_erf_approx(z.z);
        r.w = gelu_erf_approx(z.w);
        *reinterpret_cast<device float4*>(&Y[base]) = r;
    }
}

fused_qkv_projection.metal_source:
// fused_qkv_projection: y = x @ W. (S, D_in) @ (D_in, 3*D_head).
// M=128, N=192, K=512. Grid 1D, 256 thr/TG.
#include <metal_stdlib>
using namespace metal;

kernel void fused_qkv_projection_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  W        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   M        [[buffer(3)]],   // 128
    constant     uint&   N        [[buffer(4)]],   // 192
    constant     uint&   K        [[buffer(5)]],   // 512
    uint tid                     [[thread_position_in_grid]])
{
    if (tid >= M * N) return;
    const uint m = tid / N;
    const uint n = tid % N;
    // Vectorize K loop with float4. K=512, multiple of 4.
    float acc = 0.0f;
    device const float* xr = X + m * K;
    // W is (K, N) row-major; column n is strided by N=192. Not float4-friendly.
    // Process K in chunks of 4, but loading W per-k is just 4 separate loads.
    for (uint k = 0; k < K; k += 4) {
        float4 x = *reinterpret_cast<const device float4*>(&xr[k]);
        float w0 = W[(k + 0) * N + n];
        float w1 = W[(k + 1) * N + n];
        float w2 = W[(k + 2) * N + n];
        float w3 = W[(k + 3) * N + n];
        acc += x.x * w0 + x.y * w1 + x.z * w2 + x.w * w3;
    }
    Y[m * N + n] = acc;
}

attention_scores.metal_source:
// attention_scores: softmax(Q @ K^T / sqrt(D)).
// One TG per query row. S=128, D=64. TG = 1024 threads, but only first 128 do work.
#include <metal_stdlib>
using namespace metal;

kernel void attention_scores_f32(
    device const float*  Q       [[buffer(0)]],
    device const float*  K       [[buffer(1)]],
    device       float*  O       [[buffer(2)]],
    constant     uint&   S       [[buffer(3)]],
    constant     uint&   D       [[buffer(4)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint qr = tgid.y;
    if (qr >= S) return;

    threadgroup float qrow[64];      // D up to 64
    threadgroup float scores[128];   // S up to 128
    threadgroup float reduce[32];

    // Cooperatively load Q row.
    for (uint d = tid; d < D; d += TG) qrow[d] = Q[qr * D + d];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float inv = rsqrt(float(D));
    // Each of first S threads computes one score.
    if (tid < S) {
        device const float* kr = K + tid * D;
        float dot = 0.0f;
        for (uint d = 0; d < D; ++d) dot += qrow[d] * kr[d];
        scores[tid] = dot * inv;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Row max over S=128 elements.
    float v = (tid < S) ? scores[tid] : -INFINITY;
    float mx = simd_max(v);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        // 128/32 = 4 valid lanes
        float m = (tid < 4) ? reduce[tid] : -INFINITY;
        m = simd_max(m);
        if (tid == 0) reduce[0] = m;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float e = (tid < S) ? fast::exp(scores[tid] - row_max) : 0.0f;
    if (tid < S) scores[tid] = e;
    float sum = simd_sum(e);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float s = (tid < 4) ? reduce[tid] : 0.0f;
        s = simd_sum(s);
        if (tid == 0) reduce[0] = s;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_sum = 1.0f / reduce[0];

    if (tid < S) O[qr * S + tid] = scores[tid] * inv_sum;
}

nll_loss.metal_source:
// nll_loss: per-row -sum(y_onehot * log_probs). Output (N,).
#include <metal_stdlib>
using namespace metal;

kernel void nll_loss_f32(
    device const float*  LP       [[buffer(0)]],   // log_probs (N, C)
    device const float*  Yh       [[buffer(1)]],   // one-hot (N, C)
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* lp = LP + row * C;
    device const float* yp = Yh + row * C;
    threadgroup float reduce[32];

    float nll = 0.0f;
    for (uint i = tid; i < C; i += TG) nll += -yp[i] * lp[i];
    nll = simd_sum(nll);
    if ((tid & 31) == 0) reduce[tid >> 5] = nll;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        nll = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) nll += simd_shuffle_down(nll, s);
        if (tid == 0) out[row] = nll;
    }
}

log_softmax_cross_entropy.metal_source:
// log_softmax_cross_entropy: same as cross_entropy_loss, single pass per row.
// Output shape (N,).
#include <metal_stdlib>
using namespace metal;

kernel void log_softmax_cross_entropy_f32(
    device const float*  L        [[buffer(0)]],
    device const float*  Yh       [[buffer(1)]],
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* lp = L  + row * C;
    device const float* yp = Yh + row * C;
    threadgroup float reduce[32];

    float mx = -INFINITY;
    for (uint i = tid; i < C; i += TG) mx = fmax(mx, lp[i]);
    mx = simd_max(mx);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        mx = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) mx = fmax(mx, simd_shuffle_down(mx, s));
        if (tid == 0) reduce[0] = mx;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float sum = 0.0f;
    for (uint i = tid; i < C; i += TG) sum += exp(lp[i] - row_max);
    sum = simd_sum(sum);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) sum += simd_shuffle_down(sum, s);
        if (tid == 0) reduce[0] = sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float lse = row_max + log(reduce[0]);

    float nll = 0.0f;
    for (uint i = tid; i < C; i += TG) nll += yp[i] * (lse - lp[i]);
    nll = simd_sum(nll);
    if ((tid & 31) == 0) reduce[tid >> 5] = nll;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        nll = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) nll += simd_shuffle_down(nll, s);
        if (tid == 0) out[row] = nll;
    }
}

gelu_linear.metal_source:
// gelu_linear: y = gelu(x @ W). Fused matmul + erf-GELU in store phase.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

static inline float erf_approx(float z) {
    float t = 1.0f / (1.0f + 0.3275911f * fabs(z));
    float y = 1.0f - (((((1.061405429f * t - 1.453152027f) * t)
              + 1.421413741f) * t - 0.284496736f) * t + 0.254829592f)
              * t * exp(-z * z);
    return copysign(y, z);
}
static inline float4 gelu4(float4 v) {
    const float k = 0.70710678f; // 1/sqrt(2)
    float4 r;
    r.x = 0.5f * v.x * (1.0f + erf_approx(v.x * k));
    r.y = 0.5f * v.y * (1.0f + erf_approx(v.y * k));
    r.z = 0.5f * v.z * (1.0f + erf_approx(v.z * k));
    r.w = 0.5f * v.w * (1.0f + erf_approx(v.w * k));
    return r;
}

constant constexpr uint BM  = 64, BN  = 64, BK  = 16;
constant constexpr uint SM  = 16, SN  = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;

kernel void gelu_linear_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float shared[2 * BM * LDA + 2 * BK * LDB];
    threadgroup float (*As)[BM * LDA] = (threadgroup float (*)[BM * LDA]) &shared[0];
    threadgroup float (*Bs)[BK * LDB] = (threadgroup float (*)[BK * LDB]) &shared[2 * BM * LDA];
    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM, c_col0 = tgid.x * BN;
    const uint a_row = lid / 4, a_c4 = lid % 4, b_row = lid / 16, b_c4 = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    { // Prologue
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    const uint num_k_tiles = K / BK; uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf, k0_nxt = (kt + 1) * BK;
        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup); buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    threadgroup_barrier(mem_flags::mem_threadgroup);
    threadgroup float* Cs = &shared[0];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j], &Cs[(sm*SM + i*8) * BN + sn*SN + j*8], BN);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint total_f4 = BM * BN / 4;
    #pragma unroll
    for (uint idx = lid; idx < total_f4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
        *reinterpret_cast<device float4*>(&C[(c_row0 + r) * N + (c_col0 + c)]) = gelu4(v);
    }
}

rms_norm_linear.metal_source:
// rms_norm_linear: y = rms_norm(x) @ W. Two-pass: sumsq reduction, then normalized matmul.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM  = 64, BN  = 64, BK  = 16;
constant constexpr uint SM  = 16, SN  = 32, SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;

kernel void rms_norm_linear_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    constant     float&  eps [[buffer(6)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float As[2][BM * LDA], Bs[2][BK * LDB];
    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM, c_col0 = tgid.x * BN;
    const uint a_row = lid / 4, a_c4 = lid % 4, b_row = lid / 16, b_c4 = lid % 16;

    // Pass 1: per-row sumsq. RMS norm is per-row of A; we need inv_rms for each
    // row in this BM-tile (a_row in [0, BM)). Each row processed by 4 threads
    // sharing a_row → use float4 accumulators across K, then simd-reduce within
    // the row's 4 threads via lane mask.
    threadgroup float inv_rms_row[BM];
    {
        float acc = 0.0f;
        // 4 threads per row (a_c4 = 0..3) each handle K/4 elements stride 4 floats.
        for (uint k = a_c4 * 4; k < K; k += 16) {
            float4 v = *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k]);
            acc += v.x * v.x + v.y * v.y + v.z * v.z + v.w * v.w;
        }
        // Reduce across 4 threads with same a_row. They occupy 4 consecutive lanes
        // within their simd? lid = a_row*4 + a_c4. With simd size 32, lanes 0..31
        // hold a_row=0..7. So 4 threads with same a_row are adjacent.
        acc += simd_shuffle_xor(acc, 1);
        acc += simd_shuffle_xor(acc, 2);
        if (a_c4 == 0) inv_rms_row[a_row] = rsqrt(acc / float(K) + eps);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_rms = inv_rms_row[a_row];

    // Pass 2: matmul with normalized A
    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        float4 v = *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row*LDA + a_c4*4]) = inv_rms * v;
        // B is (N, K) effectively (we compute A @ B.T). Load Bs[k, n] = B[n, k].
        // b_row in [0, BK), b_c4 in [0, BN/4) → 4 cols of N.
        {
            uint k0 = b_row;
            uint n0 = c_col0 + b_c4 * 4;
            float4 v;
            v.x = B[(n0 + 0) * K + k0];
            v.y = B[(n0 + 1) * K + k0];
            v.z = B[(n0 + 2) * K + k0];
            v.w = B[(n0 + 3) * K + k0];
            *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row*LDB + b_c4*4]) = v;
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    const uint nkt = K / BK; uint buf = 0;

    for (uint kt = 0; kt < nkt - 1; ++kt) {
        const uint next = 1 - buf, k0 = (kt + 1) * BK;
        float4 v = *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row)*K + k0 + a_c4*4]);
        *reinterpret_cast<threadgroup float4*>(&As[next][a_row*LDA + a_c4*4]) = inv_rms * v;
        {
            uint kk = k0 + b_row;
            uint nn = c_col0 + b_c4 * 4;
            float4 v;
            v.x = B[(nn + 0) * K + kk];
            v.y = B[(nn + 1) * K + kk];
            v.z = B[(nn + 2) * K + kk];
            v.w = B[(nn + 3) * K + kk];
            *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row*LDB + b_c4*4]) = v;
        }
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> Ab[MMA_M], Bb[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i) simdgroup_load(Ab[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) simdgroup_load(Bb[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], Ab[i], Bb[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup); buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> Ab[MMA_M], Bb[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i) simdgroup_load(Ab[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) simdgroup_load(Bb[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], Ab[i], Bb[j], C_acc[i][j]);
    }

    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j], &C[(c_row0+sm*SM+i*8)*N+(c_col0+sn*SN+j*8)], N);
}
